#include<bits/stdc++.h>
using namespace std;
string pan(long long y,long long z){
    if(y+z>140&&y*7+z*3>=800){
        return "Excellent\n";
    }else{
        return "Not excellent\n";
    }
}
int main(){
    long long n,x,y,z;
    cin>>n;
    while(n--){
        cin>>x>>y>>z;
        cout<<pan(y,z);
    }
    return 0;
}
